// TestDefaultContextAuthenticatedData tests the DefaultContext implementation.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	testCases := []struct {
		name     string
		context  DefaultContext
		expected []byte
	}{
		{
			name:     "empty context",
			context:  DefaultContext([]byte{}),
			expected: []byte{},
		},
		{
			name:     "simple context",
			context:  DefaultContext([]byte("test-data")),
			expected: []byte("test-data"),
		},
		{
			name:     "context with special characters",
			context:  DefaultContext([]byte("\x00\x01\x02\x03")),
			expected: []byte("\x00\x01\x02\x03"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			result := tc.context.AuthenticatedData()
			if !bytes.Equal(result, tc.expected) {
				t.Errorf("AuthenticatedData() = %v, want %v", result, tc.expected)
			}
		})
	}
}

// TestTransformerRoundTrip tests basic encrypt/decrypt round-trip behavior.
func TestTransformerRoundTrip(t *testing.T) {
	originalData := []byte("secret-data")
	encryptedData := []byte("encrypted-data")

	transformer := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			if !bytes.Equal(data, originalData) {
				return nil, fmt.Errorf("unexpected input data")
			}
			return encryptedData, nil
		},
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			if !bytes.Equal(data, encryptedData) {
				return nil, false, fmt.Errorf("unexpected encrypted data")
			}
			return originalData, false, nil
		},
	}

	ctx := context.Background()

	// Encrypt
	encrypted, err := transformer.TransformToStorage(ctx, originalData, nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}
	if !bytes.Equal(encrypted, encryptedData) {
		t.Errorf("TransformToStorage = %v, want %v", encrypted, encryptedData)
	}

	// Decrypt
	decrypted, stale, err := transformer.TransformFromStorage(ctx, encrypted, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}
	if !bytes.Equal(decrypted, originalData) {
		t.Errorf("TransformFromStorage = %v, want %v", decrypted, originalData)
	}
	if stale {
		t.Error("TransformFromStorage returned stale=true, want false")
	}
}

// TestPrefixTransformerEncryptDecrypt tests PrefixTransformer with encryption/decryption.
func TestPrefixTransformerEncryptDecrypt(t *testing.T) {
	prefix := []byte("test:enc:")
	originalData := []byte("plaintext")
	encryptedData := []byte("ciphertext")

	transformer := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			return encryptedData, nil
		},
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return originalData, false, nil
		},
	}

	pt := NewPrefixTransformers(fmt.Errorf("no transformer found"),
		PrefixTransformer{
			Prefix:      prefix,
			Transformer: transformer,
		},
	)

	ctx := context.Background()

	// Test encryption
	encrypted, err := pt.TransformToStorage(ctx, originalData, nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}
	if !bytes.HasPrefix(encrypted, prefix) {
		t.Errorf("encrypted data missing prefix: %v", encrypted)
	}

	// Test decryption
	decrypted, stale, err := pt.TransformFromStorage(ctx, encrypted, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}
	if !bytes.Equal(decrypted, originalData) {
		t.Errorf("TransformFromStorage = %v, want %v", decrypted, originalData)
	}
	if stale {
		t.Error("expected stale=false for first transformer")
	}
}

// TestPrefixTransformerMultipleTransformers tests fanout-and-select logic with multiple transformers.
func TestPrefixTransformerMultipleTransformers(t *testing.T) {
	testCases := []struct {
		name            string
		prefix1         []byte
		prefix2         []byte
		prefix3         []byte
		inputData       []byte
		expectedOutput  []byte
		expectedStale   bool
		expectedErr     bool
		expectedTxIndex int
	}{
		{
			name:            "first transformer matches",
			prefix1:         []byte("first:"),
			prefix2:         []byte("second:"),
			prefix3:         []byte("third:"),
			inputData:       []byte("first:data"),
			expectedOutput:  []byte("decrypted1"),
			expectedStale:   false,
			expectedErr:     false,
			expectedTxIndex: 0,
		},
		{
			name:            "second transformer matches",
			prefix1:         []byte("first:"),
			prefix2:         []byte("second:"),
			prefix3:         []byte("third:"),
			inputData:       []byte("second:data"),
			expectedOutput:  []byte("decrypted2"),
			expectedStale:   true,
			expectedErr:     false,
			expectedTxIndex: 1,
		},
		{
			name:            "third transformer matches",
			prefix1:         []byte("first:"),
			prefix2:         []byte("second:"),
			prefix3:         []byte("third:"),
			inputData:       []byte("third:data"),
			expectedOutput:  []byte("decrypted3"),
			expectedStale:   true,
			expectedErr:     false,
			expectedTxIndex: 2,
		},
		{
			name:            "no transformer matches",
			prefix1:         []byte("first:"),
			prefix2:         []byte("second:"),
			prefix3:         []byte("third:"),
			inputData:       []byte("unknown:data"),
			expectedOutput:  nil,
			expectedStale:   false,
			expectedErr:     true,
			expectedTxIndex: -1,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			tx1 := &mockTransformer{
				transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
					return []byte("decrypted1"), false, nil
				},
			}
			tx2 := &mockTransformer{
				transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
					return []byte("decrypted2"), false, nil
				},
			}
			tx3 := &mockTransformer{
				transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
					return []byte("decrypted3"), false, nil
				},
			}

			pt := NewPrefixTransformers(
				fmt.Errorf("no matching transformer"),
				PrefixTransformer{Prefix: tc.prefix1, Transformer: tx1},
				PrefixTransformer{Prefix: tc.prefix2, Transformer: tx2},
				PrefixTransformer{Prefix: tc.prefix3, Transformer: tx3},
			)

			output, stale, err := pt.TransformFromStorage(context.Background(), tc.inputData, nil)

			if (err != nil) != tc.expectedErr {
				t.Errorf("TransformFromStorage error = %v, want error = %v", err, tc.expectedErr)
			}
			if !tc.expectedErr && !bytes.Equal(output, tc.expectedOutput) {
				t.Errorf("TransformFromStorage output = %v, want %v", output, tc.expectedOutput)
			}
			if stale != tc.expectedStale {
				t.Errorf("TransformFromStorage stale = %v, want %v", stale, tc.expectedStale)
			}
		})
	}
}

// TestPrefixTransformerErrorPropagation tests error propagation for corrupted/stale data.
func TestPrefixTransformerErrorPropagation(t *testing.T) {
	transformError := fmt.Errorf("decryption failed")
	defaultError := fmt.Errorf("default error")

	transformer := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return nil, false, transformError
		},
	}

	pt := NewPrefixTransformers(
		defaultError,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: transformer},
	)

	_, _, err := pt.TransformFromStorage(context.Background(), []byte("enc:corrupted"), nil)
	if err == nil {
		t.Fatal("expected error, got nil")
	}
	if err != transformError {
		t.Errorf("got error %v, want %v", err, transformError)
	}
}

// TestPrefixTransformerFirstTransformerForWrite tests that first transformer is used for writes.
func TestPrefixTransformerFirstTransformerForWrite(t *testing.T) {
	prefix1 := []byte("first:")
	prefix2 := []byte("second:")
	originalData := []byte("data")
	encrypted1 := []byte("encrypted1")
	encrypted2 := []byte("encrypted2")

	var firstTxUsed, secondTxUsed bool

	tx1 := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			firstTxUsed = true
			return encrypted1, nil
		},
	}
	tx2 := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			secondTxUsed = true
			return encrypted2, nil
		},
	}

	pt := NewPrefixTransformers(
		fmt.Errorf("no transformer"),
		PrefixTransformer{Prefix: prefix1, Transformer: tx1},
		PrefixTransformer{Prefix: prefix2, Transformer: tx2},
	)

	result, err := pt.TransformToStorage(context.Background(), originalData, nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	if !firstTxUsed {
		t.Error("first transformer was not used")
	}
	if secondTxUsed {
		t.Error("second transformer should not be used for write")
	}
	if !bytes.HasPrefix(result, prefix1) {
		t.Errorf("result should have first prefix, got %v", result)
	}
	if !bytes.HasSuffix(result, encrypted1) {
		t.Errorf("result should end with encrypted data from first transformer")
	}
}

// TestPrefixTransformerEmptyData tests handling of empty input data.
func TestPrefixTransformerEmptyData(t *testing.T) {
	tx := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			if len(data) != 0 {
				return nil, fmt.Errorf("expected empty data")
			}
			return []byte("empty-encrypted"), nil
		},
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return []byte{}, false, nil
		},
	}

	pt := NewPrefixTransformers(
		fmt.Errorf("no transformer"),
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: tx},
	)

	// Test encryption of empty data
	encrypted, err := pt.TransformToStorage(context.Background(), []byte{}, nil)
	if err != nil {
		t.Fatalf("TransformToStorage with empty data failed: %v", err)
	}
	if !bytes.HasPrefix(encrypted, []byte("enc:")) {
		t.Error("encrypted empty data should have prefix")
	}

	// Test decryption to empty data
	decrypted, _, err := pt.TransformFromStorage(context.Background(), encrypted, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}
	if len(decrypted) != 0 {
		t.Errorf("decrypted data should be empty, got %v", decrypted)
	}
}

// TestPrefixTransformerMismatchedPrefix tests behavior with mismatched prefix.
func TestPrefixTransformerMismatchedPrefix(t *testing.T) {
	defaultErr := fmt.Errorf("no matching transformer")
	transformer := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return []byte("data"), false, nil
		},
	}

	pt := NewPrefixTransformers(
		defaultErr,
		PrefixTransformer{Prefix: []byte("expected:"), Transformer: transformer},
	)

	// Try to decrypt data with wrong prefix
	_, _, err := pt.TransformFromStorage(context.Background(), []byte("wrong:data"), nil)
	if err == nil {
		t.Fatal("expected error for mismatched prefix")
	}
	if err != defaultErr {
		t.Errorf("got error %v, want %v", err, defaultErr)
	}
}

// TestContextInterface tests the Context interface contract.
func TestContextInterface(t *testing.T) {
	testCases := []struct {
		name        string
		ctx         Context
		expectedLen int
	}{
		{
			name:        "nil context",
			ctx:         nil,
			expectedLen: 0,
		},
		{
			name:        "default context with empty data",
			ctx:         DefaultContext([]byte{}),
			expectedLen: 0,
		},
		{
			name:        "default context with data",
			ctx:         DefaultContext([]byte("test")),
			expectedLen: 4,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			if tc.ctx == nil {
				// Skip nil context test as it would panic when calling AuthenticatedData
				return
			}
			authData := tc.ctx.AuthenticatedData()
			if len(authData) != tc.expectedLen {
				t.Errorf("AuthenticatedData length = %d, want %d", len(authData), tc.expectedLen)
			}
		})
	}
}

// TestNewPrefixTransformersWithDefaultError tests NewPrefixTransformers error handling.
func TestNewPrefixTransformersWithDefaultError(t *testing.T) {
	testCases := []struct {
		name            string
		err             error
		transformers    []PrefixTransformer
		data            []byte
		expectedErrNil  bool
		expectedErrText string
	}{
		{
			name:            "default error when no transformers",
			err:             fmt.Errorf("custom error"),
			transformers:    []PrefixTransformer{},
			data:            []byte("data"),
			expectedErrNil:  false,
			expectedErrText: "custom error",
		},
		{
			name: "default error generated when nil error provided",
			err:  nil,
			transformers: []PrefixTransformer{
				{Prefix: []byte("known:"), Transformer: &mockTransformer{}},
			},
			data:            []byte("unknown:data"),
			expectedErrNil:  false,
			expectedErrText: "does not match any of the supported transformers",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(tc.err, tc.transformers...)
			_, _, err := pt.TransformFromStorage(context.Background(), tc.data, nil)

			if (err == nil) != tc.expectedErrNil {
				t.Errorf("error nil = %v, want %v", err == nil, tc.expectedErrNil)
			}
			if err != nil && !bytes.Contains([]byte(err.Error()), []byte(tc.expectedErrText)) {
				t.Errorf("error text %q does not contain %q", err.Error(), tc.expectedErrText)
			}
		})
	}
}

// TestTransformerWriteInterface tests the Write interface.
func TestTransformerWriteInterface(t *testing.T) {
	tx := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			if ctx == nil {
				return nil, fmt.Errorf("context is nil")
			}
			return []byte("transformed"), nil
		},
	}

	// Test Write interface through Transformer
	var w Write = tx
	result, err := w.TransformToStorage(context.Background(), []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}
	if !bytes.Equal(result, []byte("transformed")) {
		t.Errorf("result = %v, want %v", result, []byte("transformed"))
	}
}

// TestTransformerReadInterface tests the Read interface.
func TestTransformerReadInterface(t *testing.T) {
	tx := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return []byte("plaintext"), true, nil
		},
	}

	// Test Read interface through Transformer
	var r Read = tx
	result, stale, err := r.TransformFromStorage(context.Background(), []byte("encrypted"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}
	if !bytes.Equal(result, []byte("plaintext")) {
		t.Errorf("result = %v, want %v", result, []byte("plaintext"))
	}
	if !stale {
		t.Error("expected stale=true")
	}
}

// TestPrefixTransformerWithContextData tests transformers with authenticated context data.
func TestPrefixTransformerWithContextData(t *testing.T) {
	receivedCtx := false

	tx := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			if dataCtx != nil && dataCtx.AuthenticatedData() != nil {
				receivedCtx = true
			}
			return data, false, nil
		},
	}

	pt := NewPrefixTransformers(
		fmt.Errorf("no transformer"),
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: tx},
	)

	dataCtx := DefaultContext([]byte("authenticated-data"))
	_, _, err := pt.TransformFromStorage(context.Background(), []byte("enc:data"), dataCtx)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}
	if !receivedCtx {
		t.Error("context data was not passed to transformer")
	}
}

