					return []byte("decrypted1"), false, nil
				},
			}
			tx2 := &mockTransformer{
				transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
					return []byte("decrypted2"), false, nil
				},
			}
			tx3 := &mockTransformer{
				transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
