// TestNewPrefixTransformersWithDefaultError tests NewPrefixTransformers error handling.
func TestNewPrefixTransformersWithDefaultError(t *testing.T) {
	testCases := []struct {
		name            string
		err             error
		transformers    []PrefixTransformer
		data            []byte
		expectedErrNil  bool
		expectedErrText string
	}{
		{
			name:            "default error when no transformers",
			err:             fmt.Errorf("custom error"),
			transformers:    []PrefixTransformer{},
			data:            []byte("data"),
			expectedErrNil:  false,
			expectedErrText: "custom error",
		},
		{
			name: "default error generated when nil error provided",
			err:  nil,
			transformers: []PrefixTransformer{
				{Prefix: []byte("known:"), Transformer: &mockTransformer{}},
			},
			data:            []byte("unknown:data"),
			expectedErrNil:  false,
			expectedErrText: "does not match any of the supported transformers",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(tc.err, tc.transformers...)
			_, _, err := pt.TransformFromStorage(context.Background(), tc.data, nil)

